import React, { useState } from 'react';

export default function TextFrom(props) {
  const handleUpClick = () => {
    console.log("Uppercase was clicked");
    let newText = text.toUpperCase();
    setText(newText)
}
const handleOnChange = (event) => {
  console.log("On change");
  setText(event.target.value);
}
    const [text, setText] = useState("Enter Your Text");
  return (
    <>
      <form>
        <div className="container my-3">
            <h1>{props.heading}</h1>
          <div className="form-group">
          <textarea className='form-Control' value={text} onChange={handleOnChange} id='mybox' rows= '6' column="7"></textarea>
          </div>
        <button type="button" className="btn btn-primary" onClick={handleUpClick}>ConvertToUpperCase</button>
        </div>
        <div className="container">
          <h1>Your Summary </h1>
          <p>Words is:{text.split("  ").length} and charachter is:{text.length}</p>
        </div>
      </form>
    </>
  );
}
